def find_matching_end(toks, p, level):
    while p < 列表长度(toks):
        tok = 列表获取(toks, p)
        if 列表获取(tok, 0) == "KW":
            tv = 列表获取(tok, 1)
            if tv == "如果":
                level = level + 1
            if tv == "当":
                level = level + 1
            if tv == "遍历":
                level = level + 1
            if tv == "类":
                level = level + 1
            if tv == "段落":
                level = level + 1
            if tv == "段":
                level = level + 1
            if tv == "否则":
                if level == 1:
                    return p
            if tv == "结束":
                if level == 1:
                    return p + 1
                level = level - 1
        p = p + 1
    return p

