            if 已处理 == 假 and 列表获取(tok, 0) == "ID":
                np = p + 1
                if np < 列表长度(toks):
                    ntok = 列表获取(toks, np)
                    if 列表获取(ntok, 0) == "LPAREN":
                        结果 = 表达式(toks, p)
