def add_indent(text, indent):
    有尾换行 = 假
    if 字符串长度(text) > 0:
        末字符 = 字符串获取(text, 字符串长度(text) - 1)
        if 末字符 == "\n":
            有尾换行 = 真
    if 有尾换行:
        text = 截取(text, 0, 字符串长度(text) - 1)
    结果 = indent + 加缩进行(text, indent, "", 0)
    if 有尾换行:
        return 结果 + "\n"
    return 结果

def 加缩进行(text, indent, acc, i):
    while i < 字符串长度(text):
        c = 字符串获取(text, i)
        if c == "\n":
            acc = acc + "\n" + indent
        
        else:
            acc = acc + c
        i = i + 1
    return acc

def comp_if(toks, p):
    if p < 列表长度(toks):
        tok = 列表获取(toks, p)
        if 列表获取(tok, 1) == "如果":
            np = p + 1
            结果 = 表达式(toks, np)
            cond = 列表获取(结果, 0)
            np = 列表获取(结果, 1)
            end_p = find_matching_end(toks, np, 1)
            body = compile_block(toks, np, end_p - 1, "    ", "")
            if body == "":
                body = "    pass\n"
            code = "if " + cond + ":\n" + body
            if end_p < 列表长度(toks):
                next_tok = 列表获取(toks, end_p)
                if 列表获取(next_tok, 1) == "否则":
                    else_p = end_p + 1
                    else_end = find_matching_end(toks, else_p, 1)
                    else_body = compile_block(toks, else_p, else_end - 1, "    ", "")
                    if else_body == "":
                        else_body = "    pass"
                    code = code + "\nelse:\n" + else_body
                    return 列表创建(code, else_end)
            return 列表创建(code, end_p)
    return 列表创建("", p)

