def 解析参数(toks, p):
    if p < 列表长度(toks):
        tok = 列表获取(toks, p)
        if 列表获取(tok, 1) == "接收":
            return 收集参数(toks, p + 1, "")
    return 列表创建("", p)

def 收集参数(toks, p, acc):
    while p < 列表长度(toks):
        tok = 列表获取(toks, p)
        已处理 = 假
        if 列表获取(tok, 0) == "ID":
            v = 列表获取(tok, 1)
            if 字符串长度(v) > 0:
                末字符 = 字符串获取(v, 字符串长度(v) - 1)
                if 末字符 == "：":
                    v = 截取(v, 0, 字符串长度(v) - 1)
                    if acc == "":
                        return 列表创建(v, p + 1)
                    return 列表创建(acc + ", " + v, p + 1)
            if acc == "":
                acc = v
            
            else:
                acc = acc + ", " + v
            p = p + 1
            已处理 = 真
        if 已处理 == 假 and 列表获取(tok, 0) == "KW":
            v = 列表获取(tok, 1)
            if v == "己":
                if acc == "":
                    acc = v
                
                else:
                    acc = acc + ", " + v
                p = p + 1
                已处理 = 真
        if 已处理 == 假 and 列表获取(tok, 0) == "COMMA":
            p = p + 1
            已处理 = 真
        if 已处理 == 假:
            return 列表创建(acc, p)
    return 列表创建(acc, p)

def compile_class(toks, p):
    if p < 列表长度(toks):
        tok = 列表获取(toks, p)
        if 列表获取(tok, 1) == "类":
            np = p + 1
            name = ""
            if np < 列表长度(toks):
                name_tok = 列表获取(toks, np)
                name = 列表获取(name_tok, 1)
                np = np + 1
            parent_name = ""
            if np < 列表长度(toks):
                next_tok = 列表获取(toks, np)
                if 列表获取(next_tok, 0) == "LPAREN":
                    np = np + 1
                    if np < 列表长度(toks):
                        parent_tok = 列表获取(toks, np)
                        parent_name = 列表获取(parent_tok, 1)
                        np = np + 1
                        if np < 列表长度(toks):
                            rparen_tok = 列表获取(toks, np)
                            if 列表获取(rparen_tok, 0) == "RPAREN":
                                np = np + 1
            end_p = find_matching_end(toks, np, 1)
            body = compile_class_body(toks, np, end_p - 1, name)
            if body == "":
                body = "    pass"
            class_def = "class " + name
            if parent_name != "":
                class_def = class_def + "(" + parent_name + ")"
            class_def = class_def + ":\n" + body
            return 列表创建(class_def, end_p)
    return 列表创建("", p)

def compile_class_body(toks, p, end_p, class_name):
    out = ""
    while p < end_p and p < 列表长度(toks):
        tok = 列表获取(toks, p)
        tv = 列表获取(tok, 1)
        已处理 = 假
        if tv == "属性":
            np = p + 1
            if np < 列表长度(toks):
                p = np + 1
                已处理 = 真
        if 已处理 == 假 and 是函数关键字(tv):
            func结果 = compile_class_method(toks, p, class_name)
            method_code = 列表获取(func结果, 0)
            p = 列表获取(func结果, 1)
            out = out + method_code
            已处理 = 真
        if 已处理 == 假 and tv == "结束":
            return out
        if 已处理 == 假:
            p = p + 1
    return out

def compile_class_method(toks, p, class_name):
    tok = 列表获取(toks, p)
    np = p + 1
    name = ""
    if np < 列表长度(toks):
        name_tok = 列表获取(toks, np)
        name = 列表获取(name_tok, 1)
        np = np + 1
    参数结果 = 解析参数(toks, np)
    params = 列表获取(参数结果, 0)
    np = 列表获取(参数结果, 1)
    final_params = ""
    if params == "己":
        final_params = "self"
    if params != "己" and 字符串长度(params) >= 2:
        前两字 = 截取(params, 0, 2)
        if 前两字 == "己,":
            final_params = "self" + 截取(params, 1, 字符串长度(params))
    if final_params == "":
        final_params = "self"
        if params != "":
            final_params = "self, " + params
    method_end = find_matching_end(toks, np, 1)
    body = compile_block(toks, np, method_end - 1, "        ", "")
    if body == "":
        body = "        pass"
    code = "    def " + name + "(" + final_params + "):\n" + body + "\n"
    return 列表创建(code, method_end)

def compile_top(toks, p, out):
    while p < 列表长度(toks):
        tok = 列表获取(toks, p)
        tv = 列表获取(tok, 1)
        已处理 = 假
        if tv == "类":
            结果 = compile_class(toks, p)
            class_code = 列表获取(结果, 0)
            np = 列表获取(结果, 1)
            out = out + class_code + "\n"
            p = np
            已处理 = 真
        if 已处理 == 假 and 是函数关键字(tv):
            结果 = compile_single_func(toks, p)
            func_code = 列表获取(结果, 0)
            np = 列表获取(结果, 1)
            out = out + func_code
            p = np
            已处理 = 真
        if 已处理 == 假:
            p = p + 1
    return out

def compile_single_func(toks, p):
    tok = 列表获取(toks, p)
    np = p + 1
    name = ""
    if np < 列表长度(toks):
        tok = 列表获取(toks, np)
        if 列表获取(tok, 0) == "ID":
            name = 列表获取(tok, 1)
            np = np + 1
    参数结果 = 解析参数(toks, np)
    params = 列表获取(参数结果, 0)
    np = 列表获取(参数结果, 1)
    body结果 = compile_stmts(toks, np, "")
    body = 列表获取(body结果, 0)
    np = 列表获取(body结果, 1)
    if body == "":
        body = "    pass\n"
    code = "def " + name + "(" + params + "):\n" + body + "\n"
    return 列表创建(code, np)

def 压缩代码(src):
    n = 字符串长度(src)
    out = ""
    p = 0
    行缓冲 = ""
    换行计数 = 0
    while p < n:
        c = 字符串获取(src, p)
        if c == "\n":
            修剪后 = ""
            i = 字符串长度(行缓冲) - 1
            继续循环 = 真
            while 继续循环 and i >= 0:
                ch = 字符串获取(行缓冲, i)
                if ch != " " and ch != "\t":
                    修剪后 = 截取(行缓冲, 0, i + 1)
                    继续循环 = 假
                
                else:
                    i = i - 1
            if 修剪后 == "":
                换行计数 = 换行计数 + 1
                if 换行计数 <= 1:
                    out = out + "\n"
                
                else:
                    换行计数 = 0
                    out = out + 修剪后 + "\n"
            
            else:
                换行计数 = 0
                out = out + 修剪后 + "\n"
            行缓冲 = ""
        
        else:
            行缓冲 = 行缓冲 + c
        p = p + 1
    if 行缓冲 != "":
        out = out + 行缓冲
    return out

def 编译(src):
    header = "# Generated by Duan Level 4\n"
    toks = 词法(src)
    code = compile_top(toks, 0, "")
    result = header + code
    return 压缩代码(result)

